// Extract search query from message
const message = $json.message || '';

// Remove UMKM keyword and get search term
let query = message
  .replace(/umkm/gi, '')
  .replace(/produk/gi, '')
  .replace(/cari/gi, '')
  .trim();

// If no query, use default
if (!query || query.length < 2) {
  query = ''; // Will return all
}

return {
  json: {
    ...$json,
    query: query
  }
};

// Format UMKM results with phone masking
const data = $json.data || [];
const query = $('Extract UMKM Query').item.json.query;

// Limit to 5 results
const results = data.slice(0, 5);

if (results.length === 0) {
  return {
    json: {
      phone: $('Extract UMKM Query').item.json.phone,
      chatId: $('Extract UMKM Query').item.json.chatId,
      reply: `❌ *TIDAK DITEMUKAN*\n\nTidak ada produk UMKM dengan kata kunci "${query}"\n\n💡 Coba kata kunci lain seperti:\n• Kerupuk\n• Makanan\n• Minuman\n• Kerajinan`
    }
  };
}

// Format each result
let replyText = `🛒 *HASIL PENCARIAN UMKM*\n`;
if (query) replyText += `Kata kunci: "${query}"\n`;
replyText += `Ditemukan: ${data.length} produk\n`;
replyText += `───────────────────\n\n`;

results.forEach((item, index) => {
  // Mask phone number
  const phone = item.whatsapp || item.phone || '';
  const maskedPhone = phone.length > 8 
    ? phone.substring(0, 4) + '****' + phone.substring(phone.length - 4)
    : phone;

  // Generate WA link
  const waLink = `https://wa.me/${phone.replace(/[^0-9]/g, '')}`;

  replyText += `${index + 1}. *${item.nama_usaha || item.name}*\n`;
  replyText += `   📍 ${item.desa || item.alamat || '-'}\n`;
  if (item.produk || item.product) {
    replyText += `   📦 ${item.produk || item.product}\n`;
  }
  replyText += `   📱 ${maskedPhone}\n`;
  replyText += `   🔗 [Hubungi via WA](${waLink})\n\n`;
});

if (data.length > 5) {
  replyText += `_...dan ${data.length - 5} lainnya_\n`;
}

replyText += `\n💡 Ketik UMKM <produk> untuk pencarian spesifik`;

return {
  json: {
    phone: $('Extract UMKM Query').item.json.phone,
    chatId: $('Extract UMKM Query').item.json.chatId,
    reply: replyText
  }
};

// Error or no results
const query = $('Extract UMKM Query').item.json.query;

const replyText = `❌ *ERROR*\n\nGagal mencari data UMKM. Silakan coba lagi nanti.\n\n💡 Ketik MENU untuk melihat daftar layanan.`;

return {
  json: {
    phone: $('Extract UMKM Query').item.json.phone,
    chatId: $('Extract UMKM Query').item.json.chatId,
    reply: replyText
  }
};
